-- Create "diagnosis_auth_tickets" table
CREATE TABLE "diagnosis_auth_tickets" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "token_hash" character varying NOT NULL,
  "subject" character varying NOT NULL,
  "roles" jsonb NOT NULL,
  "session_id" character varying NOT NULL,
  "scope" character varying NOT NULL,
  "issued_at" timestamptz NOT NULL,
  "expires_at" timestamptz NOT NULL,
  "consumed_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "diagnosis_auth_tickets_token_hash_key" to table: "diagnosis_auth_tickets"
CREATE UNIQUE INDEX "diagnosis_auth_tickets_token_hash_key" ON "diagnosis_auth_tickets" ("token_hash");
-- Create index "diagnosisauthticket_consumed_at_expires_at" to table: "diagnosis_auth_tickets"
CREATE INDEX "diagnosisauthticket_consumed_at_expires_at" ON "diagnosis_auth_tickets" ("consumed_at", "expires_at");
-- Create index "diagnosisauthticket_expires_at" to table: "diagnosis_auth_tickets"
CREATE INDEX "diagnosisauthticket_expires_at" ON "diagnosis_auth_tickets" ("expires_at");
-- Create index "diagnosisauthticket_session_id_expires_at" to table: "diagnosis_auth_tickets"
CREATE INDEX "diagnosisauthticket_session_id_expires_at" ON "diagnosis_auth_tickets" ("session_id", "expires_at");
